window.VIRAL_QUESTIONS.push(...[{"id":"Q101","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"Treatment","difficulty":"Easy","source":"PDF p. 108","question":{"en":"A patient presents within 24 hours of primary HSV gingivostomatitis with severe pain but can swallow. Which oral regimen is appropriate?","ar":"مريض حضر خلال 24 ساعة من التهاب الفم واللثة الهربسي الأولي بألم شديد لكنه يستطيع البلع. أي نظام فموي مناسب؟"},"options":[{"letter":"A","en":"Valacyclovir 1 g twice daily for 7–10 days","ar":"فالاسيكلوفير 1 جم مرتين يوميًا لمدة 7–10 أيام"},{"letter":"B","en":"Valacyclovir 2 g once monthly","ar":"فالاسيكلوفير 2 جم مرة شهريًا"},{"letter":"C","en":"Amoxicillin for 3 days","ar":"أموكسيسيلين 3 أيام"},{"letter":"D","en":"No hydration or analgesia","ar":"دون سوائل أو مسكنات"}],"correct":"A","explanation":{"en":"Primary symptomatic oral HSV benefits from early systemic antiviral treatment; valacyclovir 1 g twice daily is a listed regimen.","ar":"تستفيد عدوى HSV الفموية الأولية المصحوبة بأعراض من مضاد فيروسات جهازي مبكر، وفالاسيكلوفير 1 جم مرتين نظام مذكور."},"reasoning":{"en":"The patient is early enough for benefit and can take oral therapy; supportive analgesia and hydration are also required.","ar":"حضر المريض مبكرًا بما يكفي للاستفادة ويستطيع العلاج الفموي، مع ضرورة المسكنات والسوائل."},"image":null},{"id":"Q102","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"Treatment","difficulty":"Easy","source":"PDF p. 108","question":{"en":"A patient recognizes the tingling prodrome of a recurrent cold sore. Which regimen is designed for a single treatment day?","ar":"مريض تعرف على الوخز البادري لقرحة برد متكررة. أي نظام مصمم ليوم علاجي واحد؟"},"options":[{"letter":"A","en":"Valacyclovir 2 g twice daily for one day","ar":"فالاسيكلوفير 2 جم مرتين خلال يوم واحد"},{"letter":"B","en":"Acyclovir 400 mg once weekly","ar":"أسيكلوفير 400 مجم مرة أسبوعيًا"},{"letter":"C","en":"Fluconazole 300 mg weekly","ar":"فلوكونازول 300 مجم أسبوعيًا"},{"letter":"D","en":"Cephalexin 500 mg four times daily","ar":"سيفالكسين 500 مجم أربع مرات"}],"correct":"A","explanation":{"en":"High-dose one-day valacyclovir is an accepted episodic regimen when initiated at the prodrome.","ar":"فالاسيكلوفير بجرعة عالية ليوم واحد نظام نوباتي مقبول عند البدء في الطور البادري."},"reasoning":{"en":"Episodic therapy loses benefit when started late, so rapid self-initiation is central.","ar":"تنخفض فائدة العلاج النوباتي عند التأخر، لذا يعد البدء الذاتي السريع أساسيًا."},"image":null},{"id":"Q103","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"Treatment","difficulty":"Easy","source":"PDF p. 108","question":{"en":"Which suppressive regimen is appropriate for frequent recurrent herpes labialis?","ar":"أي نظام وقائي مناسب للهربس الشفوي المتكرر بكثرة؟"},"options":[{"letter":"A","en":"Acyclovir 400 mg twice daily","ar":"أسيكلوفير 400 مجم مرتين يوميًا"},{"letter":"B","en":"Acyclovir 800 mg once yearly","ar":"أسيكلوفير 800 مجم مرة سنويًا"},{"letter":"C","en":"Topical antibiotic indefinitely","ar":"مضاد حيوي موضعي إلى أجل غير محدد"},{"letter":"D","en":"Aspirin prophylaxis","ar":"وقاية بالأسبرين"}],"correct":"A","explanation":{"en":"Acyclovir 400 mg twice daily is a standard suppressive regimen listed in the chapter.","ar":"أسيكلوفير 400 مجم مرتين يوميًا نظام وقائي قياسي مذكور في الفصل."},"reasoning":{"en":"Suppression is selected for frequent or severe recurrences after discussing burden and adherence.","ar":"يُختار العلاج الوقائي للنوبات الكثيرة أو الشديدة بعد مناقشة العبء والالتزام."},"image":null},{"id":"Q104","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"Treatment","difficulty":"Medium","source":"PDF p. 108","question":{"en":"A patient with HSV encephalitis is suspected clinically. What is the immediate antiviral route and drug?","ar":"يُشتبه سريريًا في التهاب دماغ بسبب HSV. ما الدواء وطريق الإعطاء الفوريان؟"},"options":[{"letter":"A","en":"IV acyclovir","ar":"أسيكلوفير وريدي"},{"letter":"B","en":"Topical acyclovir only","ar":"أسيكلوفير موضعي فقط"},{"letter":"C","en":"Oral salicylic acid","ar":"حمض ساليسيليك فموي"},{"letter":"D","en":"No antiviral until serology returns","ar":"لا مضاد فيروسات حتى ظهور السيرولوجي"}],"correct":"A","explanation":{"en":"CNS HSV is a medical emergency requiring urgent IV acyclovir.","ar":"HSV بالجهاز العصبي المركزي حالة طارئة تحتاج أسيكلوفير وريديًا فورًا."},"reasoning":{"en":"Waiting for confirmation risks irreversible neurologic injury and death.","ar":"انتظار التأكيد يعرض المريض لضرر عصبي غير عكوس والوفاة."},"image":null},{"id":"Q105","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"Treatment","difficulty":"Medium","source":"PDF p. 109","question":{"en":"What is the recommended IV acyclovir dose for neonatal HSV in the chapter?","ar":"ما جرعة أسيكلوفير الوريدي الموصى بها للهربس الوليدي في الفصل؟"},"options":[{"letter":"A","en":"60 mg/kg/day divided every 8 hours","ar":"60 مجم/كجم/يوم مقسمة كل 8 ساعات"},{"letter":"B","en":"5 mg total once","ar":"5 مجم إجماليًا مرة واحدة"},{"letter":"C","en":"800 mg orally once monthly","ar":"800 مجم فمويًا مرة شهريًا"},{"letter":"D","en":"20 mg/kg once weekly","ar":"20 مجم/كجم مرة أسبوعيًا"}],"correct":"A","explanation":{"en":"Neonatal HSV is treated with high-dose IV acyclovir 60 mg/kg/day divided every eight hours.","ar":"يُعالج الهربس الوليدي بأسيكلوفير وريدي بجرعة عالية 60 مجم/كجم/يوم مقسمة كل ثماني ساعات."},"reasoning":{"en":"Dose and duration differ from routine mucocutaneous HSV because neonatal dissemination and CNS disease are common.","ar":"تختلف الجرعة والمدة عن HSV المخاطي الجلدي المعتاد لشيوع الانتشار وإصابة الجهاز العصبي لدى حديثي الولادة."},"image":null},{"id":"Q106","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"Treatment","difficulty":"Medium","source":"PDF p. 109","question":{"en":"How long should neonatal HSV with CNS or disseminated disease be treated at minimum?","ar":"ما الحد الأدنى لمدة علاج HSV الوليدي مع إصابة الجهاز العصبي أو المرض المنتشر؟"},"options":[{"letter":"A","en":"21 days","ar":"21 يومًا"},{"letter":"B","en":"One day","ar":"يوم واحد"},{"letter":"C","en":"Three days","ar":"3 أيام"},{"letter":"D","en":"Seven days regardless of PCR","ar":"7 أيام بغض النظر عن PCR"}],"correct":"A","explanation":{"en":"CNS or disseminated neonatal HSV requires at least 21 days of IV therapy and repeat CSF assessment.","ar":"تحتاج إصابة الجهاز العصبي أو المرض المنتشر لدى الوليد إلى 21 يومًا على الأقل من العلاج الوريدي مع إعادة تقييم السائل النخاعي."},"reasoning":{"en":"A positive end-of-therapy CSF PCR requires continued treatment until clearance.","ar":"تستلزم إيجابية PCR للسائل النخاعي قرب نهاية العلاج الاستمرار حتى يصبح سلبيًا."},"image":null},{"id":"Q107","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"Treatment","difficulty":"Medium","source":"PDF p. 110","question":{"en":"Which monitoring plan is most appropriate during prolonged high-dose IV acyclovir in a neonate?","ar":"أي خطة متابعة أنسب أثناء أسيكلوفير وريدي عالي الجرعة لفترة مطولة لدى وليد؟"},"options":[{"letter":"A","en":"Renal function, hydration, ANC, and infusion site monitoring","ar":"متابعة وظائف الكلى والترطيب والعدلات وموضع التسريب"},{"letter":"B","en":"No laboratory monitoring","ar":"دون متابعة مخبرية"},{"letter":"C","en":"Only serum cholesterol","ar":"الكوليسترول فقط"},{"letter":"D","en":"Only skin photography","ar":"تصوير الجلد فقط"}],"correct":"A","explanation":{"en":"Acyclovir can cause nephrotoxicity, neutropenia, and infusion-site injury.","ar":"قد يسبب أسيكلوفير سمية كلوية ونقص عدلات وإصابة بموضع التسريب."},"reasoning":{"en":"Monitoring targets predictable toxicities and permits dose adjustment before severe harm occurs.","ar":"تستهدف المتابعة السميات المتوقعة وتسمح بضبط الجرعة قبل حدوث ضرر شديد."},"image":null},{"id":"Q108","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"Treatment","difficulty":"Medium","source":"PDF p. 116","question":{"en":"Which fever treatment is preferred for a child with uncomplicated varicella?","ar":"أي علاج للحمى يُفضل لطفل لديه جديري مائي غير معقد؟"},"options":[{"letter":"A","en":"Paracetamol (acetaminophen)","ar":"باراسيتامول"},{"letter":"B","en":"Aspirin","ar":"أسبرين"},{"letter":"C","en":"High-dose salicylate combination","ar":"تركيبة ساليسيلات عالية الجرعة"},{"letter":"D","en":"No fluids","ar":"منع السوائل"}],"correct":"A","explanation":{"en":"Paracetamol is used for fever; aspirin is avoided because of Reye syndrome.","ar":"يُستخدم الباراسيتامول للحمى ويُتجنب الأسبرين بسبب متلازمة راي."},"reasoning":{"en":"Supportive treatment must relieve symptoms without introducing preventable viral-illness toxicity.","ar":"يجب أن يخفف العلاج الداعم الأعراض دون إضافة سمية يمكن الوقاية منها أثناء المرض الفيروسي."},"image":null},{"id":"Q109","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"Treatment","difficulty":"Medium","source":"PDF p. 116","question":{"en":"An unvaccinated 15-year-old presents within 12 hours of varicella rash onset. Which oral regimen is appropriate?","ar":"مراهق غير مطعم عمره 15 عامًا حضر خلال 12 ساعة من بدء طفح الجديري. أي نظام فموي مناسب؟"},"options":[{"letter":"A","en":"Acyclovir 20 mg/kg/dose (max 800 mg) four times daily for 5 days","ar":"أسيكلوفير 20 مجم/كجم/جرعة بحد أقصى 800 مجم أربع مرات يوميًا 5 أيام"},{"letter":"B","en":"Acyclovir 20 mg once","ar":"أسيكلوفير 20 مجم مرة"},{"letter":"C","en":"Imiquimod three times weekly","ar":"إيميكويمود ثلاث مرات أسبوعيًا"},{"letter":"D","en":"No treatment because age never matters","ar":"لا علاج لأن العمر لا يهم"}],"correct":"A","explanation":{"en":"Adolescents at increased risk may receive oral acyclovir if started within 24 hours.","ar":"يمكن إعطاء المراهقين عاليي الخطورة أسيكلوفير فمويًا عند البدء خلال 24 ساعة."},"reasoning":{"en":"The early presentation and age-related severity risk make antiviral benefit more favorable.","ar":"يجعل الحضور المبكر وخطر الشدة المرتبط بالعمر فائدة المضاد الفيروسي أكثر رجحانًا."},"image":null},{"id":"Q110","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"Treatment","difficulty":"Medium","source":"PDF p. 116","question":{"en":"Which regimen is preferred for an immunocompetent adult with uncomplicated varicella?","ar":"أي نظام يُفضل لبالغ سليم المناعة لديه جديري مائي غير معقد؟"},"options":[{"letter":"A","en":"Valacyclovir 1 g orally three times daily for 5–7 days","ar":"فالاسيكلوفير 1 جم فمويًا ثلاث مرات يوميًا لمدة 5–7 أيام"},{"letter":"B","en":"Topical acyclovir only","ar":"أسيكلوفير موضعي فقط"},{"letter":"C","en":"Aspirin plus no antiviral","ar":"أسبرين دون مضاد فيروسات"},{"letter":"D","en":"Salicylic acid to every lesion","ar":"حمض الساليسيليك على كل آفة"}],"correct":"A","explanation":{"en":"Adults are treated because their complication risk is higher; valacyclovir is a convenient oral option.","ar":"يُعالج البالغون لارتفاع خطر المضاعفات، ويُعد فالاسيكلوفير خيارًا فمويًا مريحًا."},"reasoning":{"en":"Therapy should begin as early as possible, ideally within 24 hours of the rash.","ar":"ينبغي بدء العلاج بأسرع ما يمكن ويفضل خلال 24 ساعة من الطفح."},"image":null},{"id":"Q111","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"Treatment","difficulty":"Medium","source":"PDF p. 117","question":{"en":"What IV acyclovir regimen is listed for a severely immunocompromised adult with active varicella?","ar":"ما نظام أسيكلوفير الوريدي المذكور لبالغ مثبط المناعة بشدة ولديه جديري نشط؟"},"options":[{"letter":"A","en":"10 mg/kg every 8 hours","ar":"10 مجم/كجم كل 8 ساعات"},{"letter":"B","en":"1 mg/kg once weekly","ar":"1 مجم/كجم مرة أسبوعيًا"},{"letter":"C","en":"400 mg topically daily","ar":"400 مجم موضعيًا يوميًا"},{"letter":"D","en":"No antiviral while lesions remain active","ar":"لا مضاد فيروسات مع بقاء الآفات نشطة"}],"correct":"A","explanation":{"en":"Severe or immunocompromised varicella is treated with IV acyclovir 10 mg/kg every eight hours, adjusted for renal function.","ar":"يُعالج الجديري الشديد أو لدى مثبط المناعة بأسيكلوفير وريدي 10 مجم/كجم كل ثماني ساعات مع ضبط الكلى."},"reasoning":{"en":"Active non-crusted lesions indicate ongoing replication and the need for prompt therapy.","ar":"تشير الآفات النشطة غير المتقشرة إلى استمرار التكاثر والحاجة للعلاج السريع."},"image":null},{"id":"Q112","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"Treatment","difficulty":"Medium","source":"PDF p. 112","question":{"en":"A susceptible high-risk person is exposed to varicella. Which prevention may be effective if given promptly according to the chapter?","ar":"شخص قابل للعدوى وعالي الخطورة تعرض للجديري. ما الوقاية التي قد تفيد عند إعطائها سريعًا وفق الفصل؟"},"options":[{"letter":"A","en":"Varicella vaccine within about 3 days when not contraindicated","ar":"لقاح الجديري خلال نحو 3 أيام عند عدم وجود مانع"},{"letter":"B","en":"HPV vaccine after one month","ar":"لقاح HPV بعد شهر"},{"letter":"C","en":"Daily penicillin","ar":"بنسلين يومي"},{"letter":"D","en":"Topical steroid prophylaxis","ar":"وقاية بكورتيزون موضعي"}],"correct":"A","explanation":{"en":"Post-exposure varicella vaccination can prevent or attenuate disease when administered promptly to eligible people.","ar":"قد يمنع لقاح الجديري بعد التعرض المرض أو يخففه عند إعطائه سريعًا لمن يناسبه."},"reasoning":{"en":"Eligibility and immune status matter; very high-risk patients may need immune globulin instead under clinical protocols.","ar":"تهم الملاءمة والحالة المناعية، وقد يحتاج شديدو الخطورة غلوبولينًا مناعيًا وفق البروتوكولات."},"image":null},{"id":"Q113","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Treatment","difficulty":"Medium","source":"PDF p. 123","question":{"en":"Which oral antiviral regimen is preferred for uncomplicated zoster because of convenient dosing?","ar":"أي نظام فموي مضاد للفيروسات يُفضل للحزام الناري غير المعقد لسهولة الجرعات؟"},"options":[{"letter":"A","en":"Valacyclovir 1 g three times daily for 7 days","ar":"فالاسيكلوفير 1 جم ثلاث مرات يوميًا 7 أيام"},{"letter":"B","en":"Valacyclovir 500 mg once monthly","ar":"فالاسيكلوفير 500 مجم مرة شهريًا"},{"letter":"C","en":"Acyclovir cream once weekly","ar":"كريم أسيكلوفير مرة أسبوعيًا"},{"letter":"D","en":"No antiviral within 72 hours","ar":"لا مضاد فيروسات خلال 72 ساعة"}],"correct":"A","explanation":{"en":"Valacyclovir 1 g three times daily provides good bioavailability with simpler dosing than acyclovir.","ar":"يوفر فالاسيكلوفير 1 جم ثلاث مرات يوميًا توافرًا حيويًا جيدًا وجرعات أبسط من أسيكلوفير."},"reasoning":{"en":"Treatment within 72 hours speeds healing and reduces acute pain and new lesion formation.","ar":"يسرع العلاج خلال 72 ساعة الشفاء ويقلل الألم الحاد وظهور آفات جديدة."},"image":null},{"id":"Q114","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Treatment","difficulty":"Medium","source":"PDF p. 123","question":{"en":"A patient presents five days after zoster began, but new vesicles are still forming. Should antiviral therapy be started?","ar":"مريض حضر بعد خمسة أيام من بدء الحزام الناري لكن ما زالت حويصلات جديدة تظهر. هل يبدأ العلاج المضاد للفيروسات؟"},"options":[{"letter":"A","en":"Yes, because ongoing new lesion formation indicates active replication","ar":"نعم لأن ظهور آفات جديدة يعني استمرار التكاثر"},{"letter":"B","en":"No, the 72-hour rule is absolute","ar":"لا، قاعدة 72 ساعة مطلقة"},{"letter":"C","en":"Only topical antibiotic","ar":"مضاد حيوي موضعي فقط"},{"letter":"D","en":"Only aspirin","ar":"أسبرين فقط"}],"correct":"A","explanation":{"en":"Treatment after 72 hours is still indicated when new lesions are appearing or the patient is older or immunocompromised.","ar":"يبقى العلاج بعد 72 ساعة مطلوبًا عند ظهور آفات جديدة أو كبر العمر أو تثبيط المناعة."},"reasoning":{"en":"The biologic evidence of ongoing viral activity is more important than an arbitrary time cutoff.","ar":"الدليل البيولوجي على استمرار نشاط الفيروس أهم من حد زمني جامد."},"image":null},{"id":"Q115","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Treatment","difficulty":"Medium","source":"PDF p. 123","question":{"en":"Which antiviral is preferred in pregnancy when treatment of zoster is indicated?","ar":"أي مضاد فيروسات يُفضل في الحمل عند الحاجة لعلاج الحزام الناري؟"},"options":[{"letter":"A","en":"Acyclovir","ar":"أسيكلوفير"},{"letter":"B","en":"Podophyllin","ar":"بودوفيلين"},{"letter":"C","en":"Oral ketoconazole","ar":"كيتوكونازول فموي"},{"letter":"D","en":"Salicylic acid","ar":"حمض الساليسيليك"}],"correct":"A","explanation":{"en":"Acyclovir has the longest and most reassuring safety record in pregnancy among the listed antivirals.","ar":"يمتلك أسيكلوفير أطول سجل أمان مطمئن في الحمل بين مضادات الفيروسات المذكورة."},"reasoning":{"en":"Maternal and fetal context guides drug selection even when the treatment indication is clear.","ar":"يوجه سياق الأم والجنين اختيار الدواء حتى عندما تكون الحاجة للعلاج واضحة."},"image":null},{"id":"Q116","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Treatment","difficulty":"Medium","source":"PDF p. 124","question":{"en":"What is the first-line analgesic approach for mild to moderate acute zoster pain?","ar":"ما النهج المسكن الأول للألم الحاد الخفيف إلى المتوسط في الحزام الناري؟"},"options":[{"letter":"A","en":"Paracetamol or an NSAID when appropriate","ar":"باراسيتامول أو مضاد التهاب غير ستيرويدي عند الملاءمة"},{"letter":"B","en":"Long-term high-dose opioid for everyone","ar":"أفيونات عالية الجرعة طويلة المدى للجميع"},{"letter":"C","en":"No pain treatment","ar":"لا علاج للألم"},{"letter":"D","en":"Topical salicylic acid on vesicles","ar":"حمض الساليسيليك على الحويصلات"}],"correct":"A","explanation":{"en":"Simple analgesics are first-line; short-course opioids may be reserved for severe pain.","ar":"المسكنات البسيطة هي الخط الأول، وقد تُحجز الأفيونات القصيرة للألم الشديد."},"reasoning":{"en":"Pain control is an independent treatment goal and should be matched to severity and patient risk.","ar":"السيطرة على الألم هدف علاجي مستقل ويجب أن تتناسب مع الشدة وخطورة المريض."},"image":null},{"id":"Q117","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Treatment","difficulty":"Medium","source":"PDF p. 124","question":{"en":"Which drug class is a standard first-line option for postherpetic neuralgia?","ar":"أي فئة دوائية خيار قياسي من الخط الأول للألم العصبي التالي للهربس؟"},"options":[{"letter":"A","en":"Gabapentinoids such as gabapentin or pregabalin","ar":"الجابابنتينويدات مثل جابابنتين أو بريجابالين"},{"letter":"B","en":"Penicillin antibiotics","ar":"مضادات البنسلين"},{"letter":"C","en":"Antifungal azoles","ar":"مضادات الفطريات الآزولية"},{"letter":"D","en":"Topical wart acids only","ar":"أحماض الثآليل الموضعية فقط"}],"correct":"A","explanation":{"en":"Gabapentinoids, TCAs, and selected topical agents are used in multimodal PHN management.","ar":"تُستخدم الجابابنتينويدات ومضادات الاكتئاب الثلاثية وبعض العلاجات الموضعية ضمن تدبير متعدد الوسائل."},"reasoning":{"en":"Neuropathic pain requires agents that modulate neural signaling rather than routine anti-infective drugs.","ar":"يحتاج الألم العصبي أدوية تعدل الإشارات العصبية لا مضادات العدوى المعتادة."},"image":null},{"id":"Q118","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Treatment","difficulty":"Medium","source":"PDF p. 125","question":{"en":"What is the preferred treatment for disseminated herpes zoster?","ar":"ما العلاج المفضل للحزام الناري المنتشر؟"},"options":[{"letter":"A","en":"IV acyclovir 10 mg/kg every 8 hours with hospital isolation","ar":"أسيكلوفير وريدي 10 مجم/كجم كل 8 ساعات مع عزل بالمستشفى"},{"letter":"B","en":"Home salicylic acid","ar":"حمض ساليسيليك منزلي"},{"letter":"C","en":"No antiviral therapy","ar":"دون مضاد فيروسات"},{"letter":"D","en":"MMR vaccine as treatment","ar":"لقاح MMR كعلاج"}],"correct":"A","explanation":{"en":"Disseminated zoster is potentially visceral and life-threatening, requiring IV acyclovir and infection-control precautions.","ar":"الحزام الناري المنتشر قد يكون حشويًا ومهددًا للحياة ويحتاج أسيكلوفير وريديًا واحتياطات مكافحة العدوى."},"reasoning":{"en":"Once improved, therapy may be stepped down to oral valacyclovir to complete an adequate course.","ar":"بعد التحسن يمكن التحويل إلى فالاسيكلوفير فموي لإكمال مدة كافية."},"image":null},{"id":"Q119","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Treatment","difficulty":"Hard","source":"PDF p. 125","question":{"en":"Which regimen is listed for Ramsay Hunt syndrome?","ar":"أي نظام مذكور لمتلازمة رامزي هانت؟"},"options":[{"letter":"A","en":"Valacyclovir 1 g three times daily for 7–10 days plus prednisone in selected patients","ar":"فالاسيكلوفير 1 جم ثلاث مرات يوميًا 7–10 أيام مع بريدنيزون في حالات مختارة"},{"letter":"B","en":"Topical clotrimazole alone","ar":"كلوتريمازول موضعي فقط"},{"letter":"C","en":"Aspirin alone","ar":"أسبرين فقط"},{"letter":"D","en":"Observation for facial paralysis","ar":"ملاحظة شلل الوجه فقط"}],"correct":"A","explanation":{"en":"Early antiviral therapy, often combined with corticosteroid treatment, may improve facial nerve recovery.","ar":"قد يحسن العلاج المبكر المضاد للفيروسات وغالبًا مع كورتيزون تعافي العصب الوجهي."},"reasoning":{"en":"The syndrome involves a cranial nerve, so treatment is more urgent than for an uncomplicated skin-only eruption.","ar":"تتضمن المتلازمة عصبًا قحفيًا، لذا يكون العلاج أكثر إلحاحًا من طفح جلدي بسيط."},"image":null},{"id":"Q120","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Treatment","difficulty":"Hard","source":"PDF p. 131","question":{"en":"How should topical salicylic acid be used for a common wart to improve effectiveness?","ar":"كيف يُستخدم حمض الساليسيليك موضعيًا للثؤلول الشائع لتحسين الفعالية؟"},"options":[{"letter":"A","en":"Regular application after soaking/paring, continued for weeks as directed","ar":"تطبيق منتظم بعد النقع والكشط اللطيف والاستمرار لأسابيع حسب الإرشادات"},{"letter":"B","en":"One application only regardless of response","ar":"تطبيق واحد فقط مهما كانت الاستجابة"},{"letter":"C","en":"Apply to normal surrounding skin extensively","ar":"وضعه بكثرة على الجلد السليم المحيط"},{"letter":"D","en":"Inject intravenously","ar":"حقنه وريديًا"}],"correct":"A","explanation":{"en":"Salicylic acid works gradually and requires consistent application to the wart while protecting normal skin.","ar":"يعمل حمض الساليسيليك تدريجيًا ويحتاج تطبيقًا منتظمًا على الثؤلول مع حماية الجلد السليم."},"reasoning":{"en":"Adherence and correct preparation often determine success more than increasing concentration unsafely.","ar":"غالبًا يحدد الالتزام والتحضير الصحيح النجاح أكثر من رفع التركيز بصورة غير آمنة."},"image":null},{"id":"Q121","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Treatment","difficulty":"Hard","source":"PDF p. 131","question":{"en":"Which office-based treatment is commonly used for cutaneous warts and typically repeated every few weeks?","ar":"أي علاج داخل العيادة يُستخدم كثيرًا للثآليل الجلدية ويُكرر عادة كل عدة أسابيع؟"},"options":[{"letter":"A","en":"Cryotherapy with liquid nitrogen","ar":"التبريد بالنيتروجين السائل"},{"letter":"B","en":"IV acyclovir","ar":"أسيكلوفير وريدي"},{"letter":"C","en":"Oral antibiotic prophylaxis","ar":"وقاية بمضاد حيوي فموي"},{"letter":"D","en":"Measles vaccine injected into every wart routinely","ar":"حقن لقاح الحصبة في كل ثؤلول روتينيًا"}],"correct":"A","explanation":{"en":"Cryotherapy destroys infected tissue and is a common clinician-applied option.","ar":"يدمر التبريد النسيج المصاب وهو خيار شائع يطبقه الطبيب."},"reasoning":{"en":"Treatment choice balances efficacy with pain, blistering, pigmentation, location, and patient age.","ar":"يوازن الاختيار بين الفعالية والألم والفقاعات والتصبغ والمكان وعمر المريض."},"image":null},{"id":"Q122","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Treatment","difficulty":"Hard","source":"PDF p. 132","question":{"en":"Which patient-applied regimen is appropriate for selected external genital warts?","ar":"أي نظام يطبقه المريض مناسب لبعض الثآليل التناسلية الخارجية؟"},"options":[{"letter":"A","en":"Imiquimod according to the prescribed schedule","ar":"إيميكويمود وفق الجدول الموصوف"},{"letter":"B","en":"Acyclovir five times daily","ar":"أسيكلوفير خمس مرات يوميًا"},{"letter":"C","en":"Selenium sulfide shampoo","ar":"شامبو سيلينيوم سلفايد"},{"letter":"D","en":"Oral penicillin","ar":"بنسلين فموي"}],"correct":"A","explanation":{"en":"Imiquimod enhances local immune response and is approved for selected external genital warts.","ar":"يعزز إيميكويمود المناعة الموضعية ويُستخدم لبعض الثآليل التناسلية الخارجية."},"reasoning":{"en":"The patient must understand application limits and local inflammatory reactions.","ar":"يجب أن يفهم المريض حدود التطبيق والتفاعلات الالتهابية الموضعية."},"image":null},{"id":"Q123","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Treatment","difficulty":"Hard","source":"PDF p. 132","question":{"en":"Which treatment is contraindicated for genital warts during pregnancy?","ar":"أي علاج للثآليل التناسلية ممنوع أثناء الحمل؟"},"options":[{"letter":"A","en":"Podophyllotoxin/podophyllin","ar":"بودوفيلوتوكسين أو بودوفيلين"},{"letter":"B","en":"Clinician-applied trichloroacetic acid","ar":"حمض ثلاثي كلورو الأسيتيك بواسطة الطبيب"},{"letter":"C","en":"Cryotherapy","ar":"التبريد"},{"letter":"D","en":"Deferred treatment when clinically reasonable","ar":"تأجيل العلاج عند الملاءمة سريريًا"}],"correct":"A","explanation":{"en":"Podophyllin compounds have potential systemic and fetal toxicity and are avoided in pregnancy.","ar":"قد تسبب مركبات البودوفيلين سمية جهازية وجنينية لذا تُتجنب في الحمل."},"reasoning":{"en":"Pregnancy screening is a safety step before prescribing self-applied genital-wart drugs.","ar":"فحص الحمل خطوة أمان قبل وصف أدوية الثآليل التناسلية ذاتية التطبيق."},"image":null},{"id":"Q124","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Treatment","difficulty":"Hard","source":"PDF p. 133","question":{"en":"What counseling is correct after successful wart removal?","ar":"ما التوعية الصحيحة بعد إزالة الثؤلول بنجاح؟"},"options":[{"letter":"A","en":"Recurrence can occur because treatment removes lesions but may not eliminate all HPV","ar":"قد يحدث النكس لأن العلاج يزيل الآفات لكنه قد لا يقضي على كل HPV"},{"letter":"B","en":"Recurrence proves malignant transformation","ar":"النكس يثبت التحول الخبيث"},{"letter":"C","en":"The patient can never transmit HPV again immediately","ar":"لا يمكن للمريض نقل HPV مرة أخرى فورًا"},{"letter":"D","en":"All partners require systemic acyclovir","ar":"كل الشركاء يحتاجون أسيكلوفير جهازيًا"}],"correct":"A","explanation":{"en":"Destructive therapy treats visible lesions but does not guarantee eradication of latent HPV in surrounding tissue.","ar":"يعالج العلاج التدميري الآفات الظاهرة لكنه لا يضمن إزالة HPV الكامن في النسيج المحيط."},"reasoning":{"en":"Realistic counseling reduces anxiety and encourages follow-up without implying treatment failure or cancer.","ar":"تقلل التوعية الواقعية القلق وتشجع المتابعة دون اعتبار النكس فشلًا أو سرطانًا."},"image":null},{"id":"Q125","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Treatment","difficulty":"Hard","source":"PDF p. 128","question":{"en":"Which preventive intervention should accompany treatment of genital warts in an eligible unvaccinated patient?","ar":"أي تدخل وقائي ينبغي أن يصاحب علاج الثآليل التناسلية لدى مريض مؤهل غير مطعم؟"},"options":[{"letter":"A","en":"Offer HPV vaccination and safe-sex counseling","ar":"عرض لقاح HPV والتوعية بالجنس الآمن"},{"letter":"B","en":"Give varicella vaccine as wart treatment","ar":"إعطاء لقاح الجديري كعلاج للثآليل"},{"letter":"C","en":"Start lifelong antibiotics","ar":"بدء مضادات حيوية مدى الحياة"},{"letter":"D","en":"Stop cervical screening permanently","ar":"إيقاف فحص عنق الرحم نهائيًا"}],"correct":"A","explanation":{"en":"Vaccination can still protect against HPV types not yet acquired, and barrier counseling reduces transmission risk.","ar":"قد يظل التطعيم واقيًا من أنماط HPV غير المكتسبة، وتقلل التوعية بالحواجز خطر الانتقال."},"reasoning":{"en":"Treatment of existing warts does not replace prevention or routine cancer screening.","ar":"علاج الثآليل الموجودة لا يحل محل الوقاية أو فحوص السرطان الروتينية."},"image":null},{"id":"Q126","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Treatment","difficulty":"Hard","source":"PDF p. 133","question":{"en":"A wart has failed salicylic acid and multiple cryotherapy sessions. What is the next best principle?","ar":"ثؤلول لم يستجب لحمض الساليسيليك وعدة جلسات تبريد. ما المبدأ التالي الأفضل؟"},"options":[{"letter":"A","en":"Reassess the diagnosis and consider alternative therapy or biopsy if atypical","ar":"إعادة تقييم التشخيص والنظر في علاج بديل أو خزعة إذا كان غير نمطي"},{"letter":"B","en":"Continue identical therapy forever without reassessment","ar":"استمرار العلاج نفسه بلا نهاية ودون تقييم"},{"letter":"C","en":"Treat with IV acyclovir","ar":"العلاج بأسيكلوفير وريدي"},{"letter":"D","en":"Assume bacterial cellulitis","ar":"اعتبارها التهاب نسيج خلوي بكتيري"}],"correct":"A","explanation":{"en":"Recalcitrance may reflect poor adherence, immune suppression, an unsuitable modality, or a wrong diagnosis.","ar":"قد تعكس المقاومة ضعف الالتزام أو تثبيط المناعة أو عدم ملاءمة الطريقة أو خطأ التشخيص."},"reasoning":{"en":"Atypical resistant lesions deserve diagnostic reconsideration before further destructive treatment.","ar":"تحتاج الآفات غير النمطية المقاومة إعادة نظر تشخيصية قبل مزيد من العلاج التدميري."},"image":null},{"id":"Q127","topic":"hfmd-herpangina","topicEn":"HFMD and Herpangina","topicAr":"مرض اليد والقدم والفم والهربانجينا","type":"Treatment","difficulty":"Hard","source":"PDF p. 141","question":{"en":"Which supportive plan is best for painful oral HFMD lesions?","ar":"أي خطة داعمة أفضل للقرح الفموية المؤلمة في مرض اليد والقدم والفم؟"},"options":[{"letter":"A","en":"Frequent cool fluids, age-appropriate analgesia, and monitoring urine output","ar":"سوائل باردة متكررة ومسكن مناسب للعمر ومتابعة البول"},{"letter":"B","en":"Aspirin in young children","ar":"أسبرين للأطفال الصغار"},{"letter":"C","en":"Routine systemic antibiotics","ar":"مضادات حيوية جهازية روتينية"},{"letter":"D","en":"Topical wart acid inside the mouth","ar":"حمض الثآليل داخل الفم"}],"correct":"A","explanation":{"en":"The main goals are pain control and prevention of dehydration.","ar":"الهدفان الرئيسيان هما السيطرة على الألم ومنع الجفاف."},"reasoning":{"en":"Oral pain can make a benign viral illness clinically significant through poor intake.","ar":"قد يجعل ألم الفم مرضًا فيروسيًا حميدًا ذا أهمية سريرية بسبب ضعف تناول السوائل."},"image":null},{"id":"Q128","topic":"hfmd-herpangina","topicEn":"HFMD and Herpangina","topicAr":"مرض اليد والقدم والفم والهربانجينا","type":"Treatment","difficulty":"Hard","source":"PDF p. 141","question":{"en":"Are acyclovir or antibiotics routinely indicated for uncomplicated HFMD?","ar":"هل يُوصى بأسيكلوفير أو المضادات الحيوية روتينيًا لمرض اليد والقدم والفم غير المعقد؟"},"options":[{"letter":"A","en":"No; management is supportive unless a specific complication is identified","ar":"لا؛ العلاج داعم ما لم توجد مضاعفة محددة"},{"letter":"B","en":"Yes, both are mandatory","ar":"نعم كلاهما إلزامي"},{"letter":"C","en":"Only antibiotics cure enteroviruses","ar":"المضادات الحيوية تشفي الفيروسات المعوية"},{"letter":"D","en":"Acyclovir prevents every outbreak","ar":"أسيكلوفير يمنع كل التفشيات"}],"correct":"A","explanation":{"en":"HFMD is an enteroviral illness and usually resolves without specific antiviral treatment.","ar":"مرض اليد والقدم والفم عدوى بفيروس معوي وتتحسن عادة دون علاج نوعي مضاد للفيروسات."},"reasoning":{"en":"Unnecessary anti-infectives add adverse effects without targeting the causative virus.","ar":"تضيف مضادات العدوى غير الضرورية آثارًا جانبية دون استهداف الفيروس المسبب."},"image":null},{"id":"Q129","topic":"hfmd-herpangina","topicEn":"HFMD and Herpangina","topicAr":"مرض اليد والقدم والفم والهربانجينا","type":"Treatment","difficulty":"Hard","source":"PDF p. 140","question":{"en":"A child with HFMD has neurologic red flags. What is the appropriate disposition?","ar":"طفل بمرض اليد والقدم والفم لديه علامات خطر عصبية. ما التصرف المناسب؟"},"options":[{"letter":"A","en":"Urgent hospital assessment and supportive monitoring","ar":"تقييم عاجل بالمستشفى ومراقبة داعمة"},{"letter":"B","en":"Routine school attendance","ar":"الذهاب المعتاد للمدرسة"},{"letter":"C","en":"Home wart treatment","ar":"علاج ثآليل منزلي"},{"letter":"D","en":"Delay evaluation for one week","ar":"تأجيل التقييم أسبوعًا"}],"correct":"A","explanation":{"en":"Neurologic complications can progress rapidly and require monitored supportive care.","ar":"قد تتقدم المضاعفات العصبية سريعًا وتحتاج رعاية داعمة تحت المراقبة."},"reasoning":{"en":"There is no routine curative antiviral; early recognition and organ support determine outcome.","ar":"لا يوجد مضاد فيروسات شافٍ روتيني، ويحدد الاكتشاف المبكر ودعم الأعضاء النتيجة."},"image":null},{"id":"Q130","topic":"measles","topicEn":"Measles","topicAr":"الحصبة","type":"Treatment","difficulty":"Hard","source":"PDF p. 151","question":{"en":"What adjunctive treatment should be given to a hospitalized child with measles?","ar":"ما العلاج المساعد الذي ينبغي إعطاؤه لطفل محجوز بالمستشفى بسبب الحصبة؟"},"options":[{"letter":"A","en":"Age-appropriate vitamin A supplementation","ar":"فيتامين أ بجرعة مناسبة للعمر"},{"letter":"B","en":"Podophyllin","ar":"بودوفيلين"},{"letter":"C","en":"Acyclovir cream","ar":"كريم أسيكلوفير"},{"letter":"D","en":"Salicylic acid","ar":"حمض الساليسيليك"}],"correct":"A","explanation":{"en":"Vitamin A reduces measles-associated morbidity and mortality in children.","ar":"يقلل فيتامين أ المضاعفات والوفيات المرتبطة بالحصبة لدى الأطفال."},"reasoning":{"en":"It is an adjunct to supportive care and treatment of complications, not an antiviral cure.","ar":"هو علاج مساعد للرعاية الداعمة وعلاج المضاعفات وليس دواءً قاتلًا للفيروس."},"image":null},{"id":"Q131","topic":"measles","topicEn":"Measles","topicAr":"الحصبة","type":"Treatment","difficulty":"Hard","source":"PDF p. 150","question":{"en":"When are antibiotics appropriate in measles?","ar":"متى تكون المضادات الحيوية مناسبة في الحصبة؟"},"options":[{"letter":"A","en":"Only for a confirmed or strongly suspected bacterial complication","ar":"فقط لمضاعفة بكتيرية مؤكدة أو مشتبه بها بقوة"},{"letter":"B","en":"For every uncomplicated measles rash","ar":"لكل طفح حصبة غير معقد"},{"letter":"C","en":"To prevent the viral prodrome in all contacts","ar":"لمنع الطور البادري الفيروسي لدى كل المخالطين"},{"letter":"D","en":"Never, even with bacterial pneumonia","ar":"لا تستخدم أبدًا حتى مع التهاب رئوي بكتيري"}],"correct":"A","explanation":{"en":"Antibiotics do not treat measles virus but are indicated for secondary bacterial infections.","ar":"لا تعالج المضادات الحيوية فيروس الحصبة لكنها مطلوبة للعدوى البكتيرية الثانوية."},"reasoning":{"en":"Clear separation of supportive viral care and complication-directed therapy prevents both undertreatment and misuse.","ar":"يفصل هذا المبدأ بين الرعاية الفيروسية الداعمة وعلاج المضاعفات ويمنع نقص العلاج وسوء الاستخدام."},"image":null},{"id":"Q132","topic":"measles","topicEn":"Measles","topicAr":"الحصبة","type":"Treatment","difficulty":"Hard","source":"PDF p. 149","question":{"en":"What is the immediate management of a suspected measles case before confirmatory results?","ar":"ما التدبير الفوري لحالة حصبة مشتبه بها قبل نتائج التأكيد؟"},"options":[{"letter":"A","en":"Airborne isolation, diagnostic sampling, and public-health notification","ar":"العزل الهوائي وأخذ العينات وإبلاغ الصحة العامة"},{"letter":"B","en":"Keep in a shared waiting room","ar":"إبقاؤه في غرفة انتظار مشتركة"},{"letter":"C","en":"Give wart cryotherapy","ar":"إجراء تبريد للثآليل"},{"letter":"D","en":"No action until rash disappears","ar":"لا إجراء حتى يختفي الطفح"}],"correct":"A","explanation":{"en":"Infection control and notification cannot wait because measles is highly contagious.","ar":"لا يمكن تأخير مكافحة العدوى والإبلاغ لأن الحصبة شديدة العدوى."},"reasoning":{"en":"The public-health response is part of treatment because it prevents additional susceptible infections.","ar":"تُعد استجابة الصحة العامة جزءًا من التدبير لأنها تمنع إصابات إضافية بين القابلين للعدوى."},"image":null},{"id":"Q133","topic":"rubella","topicEn":"Rubella","topicAr":"الحصبة الألمانية","type":"Treatment","difficulty":"Hard","source":"PDF p. 157","question":{"en":"A nonimmune woman planning pregnancy asks how to prevent congenital rubella. What is the best advice?","ar":"امرأة غير محصنة تخطط للحمل تسأل عن منع الحصبة الألمانية الخلقية. ما أفضل نصيحة؟"},"options":[{"letter":"A","en":"Receive MMR before pregnancy and avoid conception for the recommended interval","ar":"تلقي MMR قبل الحمل وتجنب الحمل للمدة الموصى بها"},{"letter":"B","en":"Receive live MMR during pregnancy","ar":"تلقي MMR الحي أثناء الحمل"},{"letter":"C","en":"Take daily acyclovir","ar":"تناول أسيكلوفير يوميًا"},{"letter":"D","en":"Use topical antibiotics","ar":"استخدام مضادات حيوية موضعية"}],"correct":"A","explanation":{"en":"Preconception immunization protects future pregnancies; live MMR is contraindicated during pregnancy.","ar":"يوفر التطعيم قبل الحمل حماية للحمل المستقبلي، ويُمنع MMR الحي أثناء الحمل."},"reasoning":{"en":"Prevention is crucial because no post-infection treatment can reliably reverse fetal injury.","ar":"الوقاية حاسمة لأنه لا يوجد علاج بعد العدوى يعكس إصابة الجنين بصورة موثوقة."},"image":null},{"id":"Q134","topic":"fifth-disease","topicEn":"Fifth Disease","topicAr":"المرض الخامس","type":"Treatment","difficulty":"Hard","source":"PDF p. 159","question":{"en":"What is the usual treatment for uncomplicated fifth disease in a healthy child?","ar":"ما العلاج المعتاد للمرض الخامس غير المعقد لدى طفل سليم؟"},"options":[{"letter":"A","en":"Reassurance, fluids, and symptomatic care","ar":"الطمأنة والسوائل وعلاج الأعراض"},{"letter":"B","en":"Routine IV acyclovir","ar":"أسيكلوفير وريدي روتيني"},{"letter":"C","en":"Long-term antibiotics","ar":"مضادات حيوية طويلة المدى"},{"letter":"D","en":"Surgical rash removal","ar":"إزالة الطفح جراحيًا"}],"correct":"A","explanation":{"en":"Fifth disease is usually mild and self-limited in healthy children.","ar":"المرض الخامس غالبًا خفيف ومحدود ذاتيًا لدى الأطفال الأصحاء."},"reasoning":{"en":"Management changes only when pregnancy, hemolytic anemia, or immunodeficiency creates complication risk.","ar":"يتغير التدبير فقط عندما يسبب الحمل أو الأنيميا الانحلالية أو نقص المناعة خطر مضاعفات."},"image":null},{"id":"Q135","topic":"molluscum","topicEn":"Molluscum Contagiosum","topicAr":"المليساء المعدية","type":"Treatment","difficulty":"Hard","source":"PDF p. 163","question":{"en":"A child has a few asymptomatic molluscum papules and no eczema or immune problem. What is a reasonable treatment choice?","ar":"طفل لديه بضع حطاطات مليساء دون أعراض ولا إكزيما أو مشكلة مناعية. ما خيار العلاج المعقول؟"},"options":[{"letter":"A","en":"Watchful waiting with prevention counseling","ar":"الانتظار والملاحظة مع توعية الوقاية"},{"letter":"B","en":"IV antiviral therapy","ar":"علاج وريدي مضاد للفيروسات"},{"letter":"C","en":"Emergency surgery","ar":"جراحة عاجلة"},{"letter":"D","en":"Long-term systemic steroid","ar":"كورتيزون جهازي طويل المدى"}],"correct":"A","explanation":{"en":"Spontaneous resolution is common, so active treatment is optional in uncomplicated cases.","ar":"الشفاء التلقائي شائع، لذا يكون العلاج النشط اختياريًا في الحالات غير المعقدة."},"reasoning":{"en":"The decision should reflect symptoms, psychosocial burden, spread, location, eczema, and immune status.","ar":"يجب أن يعكس القرار الأعراض والعبء النفسي والانتشار والمكان والإكزيما والحالة المناعية."},"image":null},{"id":"Q136","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"Image","difficulty":"Easy","source":"PDF p. 106","question":{"en":"The image shows a febrile child with diffuse painful oral erosions and inflamed gums. Which diagnosis best fits?","ar":"تُظهر الصورة طفلًا محمومًا لديه تآكلات فموية مؤلمة منتشرة والتهاب باللثة. ما التشخيص الأنسب؟"},"options":[{"letter":"A","en":"Primary herpetic gingivostomatitis","ar":"التهاب اللثة والفم الهربسي الأولي"},{"letter":"B","en":"Recurrent localized cold sore","ar":"قرحة برد موضعية متكررة"},{"letter":"C","en":"Molluscum contagiosum","ar":"المليساء المعدية"},{"letter":"D","en":"Common wart","ar":"ثؤلول شائع"}],"correct":"A","explanation":{"en":"The diffuse oral distribution with gingivitis is characteristic of primary HSV gingivostomatitis.","ar":"التوزيع الفموي المنتشر مع التهاب اللثة مميز لالتهاب الفم واللثة الأولي بـHSV."},"reasoning":{"en":"Image recognition must be combined with fever, age, gingival inflammation, and pain; a single recurrent cold sore is much more localized.","ar":"يجب جمع التعرف البصري مع الحمى والعمر والتهاب اللثة والألم، إذ تكون قرحة البرد المتكررة أكثر موضعية."},"image":"assets/images/chapters/viral/viral-q136.webp"},{"id":"Q137","topic":"herpes-simplex","topicEn":"Herpes Simplex","topicAr":"الهربس البسيط","type":"Image","difficulty":"Easy","source":"PDF p. 107","question":{"en":"Which diagnosis is illustrated by the grouped painful vesicles on the finger?","ar":"ما التشخيص الذي توضحه الحويصلات المؤلمة المتجمعة على الإصبع؟"},"options":[{"letter":"A","en":"Herpetic whitlow","ar":"الداحس الهربسي"},{"letter":"B","en":"Plantar wart","ar":"ثؤلول أخمصي"},{"letter":"C","en":"Rubella","ar":"الحصبة الألمانية"},{"letter":"D","en":"Measles","ar":"الحصبة"}],"correct":"A","explanation":{"en":"Herpetic whitlow causes deep grouped vesicles and marked finger pain after inoculation through broken skin.","ar":"يسبب الداحس الهربسي حويصلات عميقة متجمعة وألمًا شديدًا بالإصبع بعد دخول الفيروس عبر جلد متشقق."},"reasoning":{"en":"The vesicular morphology argues against a wart, and incision and drainage are not routine as they are for a bacterial abscess.","ar":"يرفض الشكل الحويصلي تشخيص الثؤلول، ولا يُجرى الشق والتصريف روتينيًا كما في الخراج البكتيري."},"image":"assets/images/chapters/viral/viral-q137.webp"},{"id":"Q138","topic":"varicella","topicEn":"Varicella","topicAr":"الجديري المائي","type":"Image","difficulty":"Easy","source":"PDF p. 114","question":{"en":"The pictured eruption contains papules, vesicles, pustules, and crusts at the same time, mainly on the trunk. What is the diagnosis?","ar":"يحتوي الطفح المصور على حطاطات وحويصلات وبثرات وقشور في الوقت نفسه ويتركز على الجذع. ما التشخيص؟"},"options":[{"letter":"A","en":"Varicella","ar":"الجديري المائي"},{"letter":"B","en":"Localized herpes zoster","ar":"الحزام الناري الموضعي"},{"letter":"C","en":"Flat warts","ar":"ثآليل مسطحة"},{"letter":"D","en":"Molluscum contagiosum","ar":"المليساء المعدية"}],"correct":"A","explanation":{"en":"Polymorphic lesions in successive crops with a centripetal distribution are classic for chickenpox.","ar":"الآفات متعددة المراحل على دفعات مع توزيع مركزي نموذجية للجديري المائي."},"reasoning":{"en":"A generalized trunk-predominant eruption is unlike the unilateral dermatomal pattern of zoster.","ar":"يختلف الطفح المنتشر الغالب على الجذع عن النمط القطاعي أحادي الجانب للحزام الناري."},"image":"assets/images/chapters/viral/viral-q138.webp"},{"id":"Q139","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Image","difficulty":"Easy","source":"PDF p. 120","question":{"en":"Which feature in the image most strongly supports herpes zoster?","ar":"أي سمة بالصورة تدعم الحزام الناري بقوة؟"},"options":[{"letter":"A","en":"Grouped vesicles in a unilateral dermatomal band","ar":"حويصلات متجمعة في شريط قطاعي أحادي الجانب"},{"letter":"B","en":"Symmetric generalized macules","ar":"بقع متناظرة منتشرة"},{"letter":"C","en":"Central umbilication of isolated papules","ar":"تنقر مركزي لحطاطات منفردة"},{"letter":"D","en":"Cauliflower-like genital surface","ar":"سطح تناسلي شبيه بالقرنبيط"}],"correct":"A","explanation":{"en":"The image demonstrates a localized unilateral band of grouped vesicles typical of VZV reactivation.","ar":"توضح الصورة شريطًا أحادي الجانب من حويصلات متجمعة نموذجيًا لإعادة تنشيط VZV."},"reasoning":{"en":"The distribution, not merely the presence of vesicles, differentiates zoster from varicella or HSV.","ar":"التوزيع وليس وجود الحويصلات وحده هو ما يفرق الحزام الناري عن الجديري أو HSV."},"image":"assets/images/chapters/viral/viral-q139.webp"},{"id":"Q140","topic":"herpes-zoster","topicEn":"Herpes Zoster","topicAr":"الحزام الناري","type":"Image","difficulty":"Easy","source":"PDF p. 127","question":{"en":"The image shows vesicles and swelling in the ophthalmic division of the trigeminal nerve. What is the most important action?","ar":"تُظهر الصورة حويصلات وتورمًا في توزيع الفرع العيني للعصب الخامس. ما أهم إجراء؟"},"options":[{"letter":"A","en":"Urgent ophthalmology referral and systemic antiviral therapy","ar":"تحويل عاجل للعيون وعلاج جهازي مضاد للفيروسات"},{"letter":"B","en":"Use salicylic acid near the eyelid","ar":"وضع حمض الساليسيليك قرب الجفن"},{"letter":"C","en":"Observe without treatment for a month","ar":"الملاحظة دون علاج لمدة شهر"},{"letter":"D","en":"Treat as a simple wart","ar":"العلاج كثؤلول بسيط"}],"correct":"A","explanation":{"en":"Herpes zoster ophthalmicus can cause keratitis, uveitis, and vision loss.","ar":"قد يسبب الهربس العيني التهاب القرنية والعنبية وفقد البصر."},"reasoning":{"en":"Any ocular symptoms or V1 distribution require rapid antiviral treatment and specialist eye examination.","ar":"تستلزم الأعراض العينية أو توزيع V1 علاجًا سريعًا وفحصًا تخصصيًا للعين."},"image":"assets/images/chapters/viral/viral-q140.webp"},{"id":"Q141","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Image","difficulty":"Easy","source":"PDF p. 135","question":{"en":"What lesion is shown in the image?","ar":"ما الآفة الظاهرة في الصورة؟"},"options":[{"letter":"A","en":"Common wart (verruca vulgaris)","ar":"ثؤلول شائع"},{"letter":"B","en":"Molluscum contagiosum","ar":"المليساء المعدية"},{"letter":"C","en":"Herpes vesicle","ar":"حويصلة هربسية"},{"letter":"D","en":"Measles exanthem","ar":"طفح الحصبة"}],"correct":"A","explanation":{"en":"The rough hyperkeratotic papule is typical of verruca vulgaris.","ar":"الحطاطة الخشنة المتقرنة نموذجية للثؤلول الشائع."},"reasoning":{"en":"A common wart lacks the smooth pearly surface and central umbilication of molluscum and is not fluid-filled like herpes.","ar":"لا يملك الثؤلول السطح اللؤلؤي الأملس والتنقر المركزي للمليساء وليس ممتلئًا بسائل كالهربس."},"image":"assets/images/chapters/viral/viral-q141.webp"},{"id":"Q142","topic":"hpv","topicEn":"Human Papillomavirus","topicAr":"فيروس الورم الحليمي البشري","type":"Image","difficulty":"Easy","source":"PDF p. 135","question":{"en":"The image shows a hyperkeratotic painful plantar lesion with dark vascular dots. Which diagnosis is most likely?","ar":"تُظهر الصورة آفة أخمصية متقرنة مؤلمة مع نقاط وعائية داكنة. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Plantar wart","ar":"ثؤلول أخمصي"},{"letter":"B","en":"Herpetic whitlow","ar":"داحس هربسي"},{"letter":"C","en":"Rubella","ar":"حصبة ألمانية"},{"letter":"D","en":"Varicella","ar":"جديري مائي"}],"correct":"A","explanation":{"en":"Thrombosed capillary dots within a plantar hyperkeratotic lesion indicate a wart.","ar":"تشير نقاط الشعيرات المتخثرة داخل آفة أخمصية متقرنة إلى ثؤلول."},"reasoning":{"en":"Paring and pressure pattern help distinguish it from a corn or callus.","ar":"يساعد الكشط ونمط الألم بالضغط على تمييزه عن مسمار القدم أو الكالو."},"image":"assets/images/chapters/viral/viral-q142.webp"},{"id":"Q143","topic":"hfmd-herpangina","topicEn":"HFMD and Herpangina","topicAr":"مرض اليد والقدم والفم والهربانجينا","type":"Image","difficulty":"Easy","source":"PDF p. 137","question":{"en":"Which diagnosis best fits the pictured acral vesicles when accompanied by painful oral ulcers in a young child?","ar":"ما التشخيص الأنسب للحويصلات الطرفية المصورة عندما تصاحبها قرح فموية مؤلمة لدى طفل صغير؟"},"options":[{"letter":"A","en":"Hand-foot-and-mouth disease","ar":"مرض اليد والقدم والفم"},{"letter":"B","en":"Herpes zoster","ar":"الحزام الناري"},{"letter":"C","en":"Genital HPV","ar":"HPV التناسلي"},{"letter":"D","en":"Molluscum contagiosum","ar":"المليساء المعدية"}],"correct":"A","explanation":{"en":"Acral lesions on hands or feet plus oral ulcers form the classic HFMD pattern.","ar":"تكوّن الآفات الطرفية على اليدين أو القدمين مع القرح الفموية النمط الكلاسيكي لمرض اليد والقدم والفم."},"reasoning":{"en":"The age and oral-acral combination distinguish the illness from a dermatomal herpes eruption.","ar":"يميز العمر واجتماع الآفات الفموية والطرفية المرض عن طفح هربسي قطاعي."},"image":"assets/images/chapters/viral/viral-q143.webp"},{"id":"Q144","topic":"measles","topicEn":"Measles","topicAr":"الحصبة","type":"Image","difficulty":"Easy","source":"PDF p. 147","question":{"en":"The oral finding in the image appears before a generalized rash. What is it?","ar":"تظهر العلامة الفموية في الصورة قبل طفح منتشر. ما هي؟"},"options":[{"letter":"A","en":"Koplik spots","ar":"بقع كوبليك"},{"letter":"B","en":"Oral candidiasis","ar":"فطريات الفم"},{"letter":"C","en":"Molluscum papules","ar":"حطاطات المليساء"},{"letter":"D","en":"Aphthous ulcers only","ar":"قرح قلاعية فقط"}],"correct":"A","explanation":{"en":"Koplik spots are tiny bluish-white lesions on an erythematous buccal background and strongly support measles.","ar":"بقع كوبليك آفات صغيرة بيضاء مزرقة على خلفية مخاطية حمراء وتدعم تشخيص الحصبة بقوة."},"reasoning":{"en":"With fever, cough, coryza, and conjunctivitis, this image should trigger airborne isolation before the skin rash appears.","ar":"مع الحمى والسعال والرشح والتهاب الملتحمة يجب أن تؤدي الصورة إلى العزل الهوائي قبل ظهور الطفح الجلدي."},"image":"assets/images/chapters/viral/viral-q144.webp"},{"id":"Q145","topic":"fifth-disease","topicEn":"Fifth Disease","topicAr":"المرض الخامس","type":"Image","difficulty":"Easy","source":"PDF p. 159","question":{"en":"Which viral exanthem is suggested by the bright “slapped-cheek” facial erythema in the image?","ar":"أي طفح فيروسي يوحي به احمرار الوجه الشديد كأنه «صفعة» في الصورة؟"},"options":[{"letter":"A","en":"Erythema infectiosum due to parvovirus B19","ar":"الحمامى المعدية بسبب بارفو B19"},{"letter":"B","en":"Varicella","ar":"الجديري المائي"},{"letter":"C","en":"Herpes zoster","ar":"الحزام الناري"},{"letter":"D","en":"Molluscum contagiosum","ar":"المليساء المعدية"}],"correct":"A","explanation":{"en":"The slapped-cheek appearance is the hallmark early rash of fifth disease.","ar":"مظهر الخدين المصفوعين هو العلامة المبكرة المميزة للمرض الخامس."},"reasoning":{"en":"A later lacy reticular rash on the limbs and trunk would further support the diagnosis.","ar":"يدعم التشخيص أكثر ظهور طفح شبكي دانتلي لاحقًا على الأطراف والجذع."},"image":"assets/images/chapters/viral/viral-q145.webp"},{"id":"Q146","topic":"molluscum","topicEn":"Molluscum Contagiosum","topicAr":"المليساء المعدية","type":"Image","difficulty":"Medium","source":"PDF p. 162","question":{"en":"What is the most characteristic feature of the pictured papules?","ar":"ما أكثر سمة مميزة للحطاطات المصورة؟"},"options":[{"letter":"A","en":"Central umbilication","ar":"التنقر المركزي"},{"letter":"B","en":"Dermatomal distribution","ar":"التوزيع القطاعي"},{"letter":"C","en":"Honey-colored crust","ar":"قشرة بلون العسل"},{"letter":"D","en":"Target configuration","ar":"شكل الهدف"}],"correct":"A","explanation":{"en":"Smooth pearly papules with a central dell are diagnostic of molluscum contagiosum.","ar":"الحطاطات الملساء اللؤلؤية ذات الانخفاض المركزي تشخص المليساء المعدية."},"reasoning":{"en":"The morphology often permits clinical diagnosis without laboratory testing in a typical child.","ar":"يسمح الشكل غالبًا بالتشخيص السريري دون فحوص مخبرية لدى طفل نموذجي."},"image":"assets/images/chapters/viral/viral-q146.webp"},{"id":"Q147","topic":"covid-cutaneous","topicEn":"COVID-19 Cutaneous Signs","topicAr":"العلامات الجلدية لكوفيد-19","type":"Image","difficulty":"Medium","source":"PDF p. 166","question":{"en":"Which descriptive term best fits the COVID-associated eruption shown?","ar":"أي وصف يناسب أكثر الطفح المرتبط بكوفيد الظاهر؟"},"options":[{"letter":"A","en":"Morbilliform maculopapular eruption","ar":"طفح بقعي حطاطي شبيه بالحصبة"},{"letter":"B","en":"Plantar wart","ar":"ثؤلول أخمصي"},{"letter":"C","en":"Herpetic whitlow","ar":"داحس هربسي"},{"letter":"D","en":"Molluscum contagiosum","ar":"مليساء معدية"}],"correct":"A","explanation":{"en":"A diffuse erythematous maculopapular pattern is described as morbilliform.","ar":"يوصف النمط الحمامي البقعي الحطاطي المنتشر بأنه شبيه بالحصبة."},"reasoning":{"en":"Because the morphology is nonspecific, medication timing and severe-drug-reaction red flags must also be assessed.","ar":"لأن الشكل غير نوعي يجب أيضًا تقييم توقيت الأدوية وعلامات التفاعل الدوائي الشديد."},"image":"assets/images/chapters/viral/viral-q147.webp"},{"id":"Q148","topic":"covid-cutaneous","topicEn":"COVID-19 Cutaneous Signs","topicAr":"العلامات الجلدية لكوفيد-19","type":"Image","difficulty":"Medium","source":"PDF p. 166","question":{"en":"The raised transient wheals in the image are best classified as what pattern?","ar":"كيف يُصنف أفضل شكل الانتبارات المرتفعة العابرة في الصورة؟"},"options":[{"letter":"A","en":"Urticarial eruption","ar":"طفح شروي"},{"letter":"B","en":"Common warts","ar":"ثآليل شائعة"},{"letter":"C","en":"Koplik spots","ar":"بقع كوبليك"},{"letter":"D","en":"Zoster sine herpete","ar":"حزام ناري دون طفح"}],"correct":"A","explanation":{"en":"Urticaria consists of raised edematous wheals that may occur during infection or as a drug reaction.","ar":"يتكون الشرى من انتبارات مرتفعة متوذمة وقد يحدث أثناء العدوى أو كتفاعل دوائي."},"reasoning":{"en":"Airway symptoms, facial swelling, and medication exposure determine urgency and cause more than the visual pattern alone.","ar":"تحدد أعراض مجرى الهواء وتورم الوجه والتعرض الدوائي الإلحاح والسبب أكثر من الشكل وحده."},"image":"assets/images/chapters/viral/viral-q148.webp"},{"id":"Q149","topic":"covid-cutaneous","topicEn":"COVID-19 Cutaneous Signs","topicAr":"العلامات الجلدية لكوفيد-19","type":"Image","difficulty":"Medium","source":"PDF p. 167","question":{"en":"Which pattern is illustrated by the net-like violaceous discoloration?","ar":"ما النمط الذي توضحه الزرقة البنفسجية الشبكية؟"},"options":[{"letter":"A","en":"Livedo reticularis/retiform vascular pattern","ar":"الشبكية الزرقاء أو النمط الوعائي الشبكي"},{"letter":"B","en":"Molluscum contagiosum","ar":"المليساء المعدية"},{"letter":"C","en":"Measles Koplik spots","ar":"بقع كوبليك للحصبة"},{"letter":"D","en":"Genital warts","ar":"الثآليل التناسلية"}],"correct":"A","explanation":{"en":"The reticular violaceous appearance reflects altered cutaneous blood flow and may be associated with vascular disease.","ar":"يعكس المظهر البنفسجي الشبكي تغير تدفق الدم الجلدي وقد يرتبط بمرض وعائي."},"reasoning":{"en":"In a severely ill patient, retiform purpura should prompt evaluation for coagulopathy or vascular occlusion.","ar":"لدى المريض شديد المرض تستدعي الفرفرية الشبكية تقييم اضطراب التخثر أو الانسداد الوعائي."},"image":"assets/images/chapters/viral/viral-q149.webp"},{"id":"Q150","topic":"covid-cutaneous","topicEn":"COVID-19 Cutaneous Signs","topicAr":"العلامات الجلدية لكوفيد-19","type":"Image","difficulty":"Medium","source":"PDF p. 167","question":{"en":"The acral erythematous-violaceous lesions in the image are commonly called what?","ar":"بماذا تُسمى شائعًا الآفات الطرفية الحمراء البنفسجية في الصورة؟"},"options":[{"letter":"A","en":"COVID toes (pernio-like lesions)","ar":"أصابع كوفيد «آفات شبيهة بالشرث»"},{"letter":"B","en":"Koplik spots","ar":"بقع كوبليك"},{"letter":"C","en":"Condyloma acuminata","ar":"الثآليل التناسلية"},{"letter":"D","en":"Herpetic gingivostomatitis","ar":"التهاب اللثة والفم الهربسي"}],"correct":"A","explanation":{"en":"Pernio-like lesions affecting the toes are commonly termed COVID toes.","ar":"تُسمى الآفات الشبيهة بالشرث التي تصيب أصابع القدم شائعًا أصابع كوفيد."},"reasoning":{"en":"The diagnosis remains clinical and contextual; cold exposure and other causes of pernio should also be considered.","ar":"يبقى التشخيص سريريًا وسياقيًا، ويجب أيضًا النظر في التعرض للبرد وأسباب الشرث الأخرى."},"image":"assets/images/chapters/viral/viral-q150.webp"}]);
